window.__QUIZ_DATA__=[{"id":"theory>Biology>2004>1>a","subject":"Biology","year":"2004","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"What is a habitat?","images":[],"marking_scheme":"A habitat is the dwelling place of an organism (plants and animals).","marks":"3","difficulty":"1"},{"id":"theory>Biology>2004>1>b","subject":"Biology","year":"2004","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE","question":"Describe the energy flow in a freshwater habitat.","images":[],"marking_scheme":"Green plants such as algae in fresh water such as pond or stream traps radiant energy from the sun to produce their food through photosynthesis. Animals in the fresh water such as zooplankton or fishes depend on the green plant for food directly if they are herbivores or indirectly if they are carnivores. Bacteria and fungi and other saprophytes (decomposers), feed on the dead plants and animals and their wastes and energy is lost.","marks":"7.5","difficulty":"2"},{"id":"theory>Biology>2004>1>c>i","subject":"Biology","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"List three biotic factors.","images":[],"marking_scheme":"- plants/producers  -animals/consumers  -parasites  -decomposers/saprophytes/micro-organisms  -predators","marks":"3.5","difficulty":"1"},{"id":"theory>Biology>2004>1>c>ii","subject":"Biology","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS","question":"List five abiotic factors which affect plants in fresh water habitat.","images":[],"marking_scheme":"The abiotic factors are:  -temperature  -sunlight/light  -wind  -inorganic compounds  -turbidity/suspended particles/transparency  -topography  -dissolved oxygen  -pH/dissolved CO2   -water currents/currents   -rainfall/precipitation","marks":"6","difficulty":"2"},{"id":"theory>Biology>2004>2>a>i","subject":"Biology","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"What is a joint?","images":[],"marking_scheme":"A joint is a connection between two bones in the body. Joints allow for varying degrees of movement and can be classified based on their structure and function","marks":"2","difficulty":"1"},{"id":"theory>Biology>2004>2>a>ii","subject":"Biology","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"List three types of movable joints and mention one location in the mammalian body of each type.","images":[],"marking_scheme":"The types of joint and their location in the body are:  - The pivot or rotating joint located in the neck region of the body.  - The ball and socket joint located in the shoulder or hip.  - The hinge joint located in the elbow, knee or phalonges.  - Sliding or gliding joint located in the wrist ankle or vertebrae.","marks":"5","difficulty":"2"},{"id":"theory>Biology>2004>2>b>i","subject":"Biology","year":"2004","type":"Theory","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Make a labelled diagram, 8 - 10cm long, of typical movable joint.","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Biology>2004>2>b>ii","subject":"Biology","year":"2004","type":"Theory","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Explain how the structure of the joint adapts it to its function.","images":[],"marking_scheme":"Adaptability of function to structure of the joint occurs when as a result of the cartilage the joint has that reduce the friction between two bones in contact. It has ligament that holds the bones together. It has synovial membrane that secretes the synovial fluid. The synovial fluid lubricates the joint and allow easy movement at the joint.","marks":"3","difficulty":"3"},{"id":"theory>Biology>2004>3>a","subject":"Biology","year":"2004","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Distinguish between pollination and fertilization in plants.","images":[],"marking_scheme":"Pollination is the transfer of pollen grains from the anther of a flower to the stigma of a flower while fertilization is the fusion of male gamete with the female gamete to form zygote. Fertilization is being preceeded by pollination.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2004>3>b>i","subject":"Biology","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"State five features which ensure cross pollination in plants.","images":[],"marking_scheme":"- Cross pollination occurs in sweet flower to attract insects e.g bees and butterfly.  - Cross pollination occur in plants with brightly coloured petals to attract insects such as Delonix, flamboyant. These animals pick up the pollen and carry it from one plant to another.  - Cross pollination also occurs in flowers that are structured to prevent self pollination since only a particular type of insect or animal can affect pollination e.g groundnut, pea, crotalaria, centrocema, vigna. In these, the stamens mature first shedding pollen into a sac-like tube formed by the keel. Honey guides on the standard petal direct the bee to the nectaries and the stigma points towards entrance of the keel and can only receive pollen brought in by a visiting bee.  - It also occurs in dioecious plants where male and female flower occur on separate plants e.g Carica papaya  - It also occurs in plants in which male and female plants mature at different times (Dichogamy) for example in plants like mistletoe and crotalaria; the carples mature before the stamen (protogyny). In sunflower and cotton stamen mature before the carpel (protandy)  - Cross pollination occurs in plants with self compatibility or self sterility where certain chemicals on the surface of the stigma prevents growth in the pollen tubes of pollens grain from the same flower","marks":"7.5","difficulty":"2"},{"id":"theory>Biology>2004>3>b>ii","subject":"Biology","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Name one plant example for each feature.","images":[],"marking_scheme":"- Cross pollination occurs in sweet flower to attract insects e.g bees and butterfly.  - Cross pollination occur in plants with brightly coloured petals to attract insects such as Delonix, flamboyant. These animals pick up the pollen and carry it from one plant to another.  - Cross pollination also occurs in flowers that are structured to prevent self pollination since only a particular type of insect or animal can affect pollination e.g groundnut, pea, crotalaria, centrocema, vigna. In these, the stamens mature first shedding pollen into a sac-like tube formed by the keel. Honey guides on the standard petal direct the bee to the nectaries and the stigma points towards entrance of the keel and can only receive pollen brought in by a visiting bee.  - It also occurs in dioecious plants where male and female flower occur on separate plants e.g Carica papaya  - It also occurs in plants in which male and female plants mature at different times (Dichogamy) for example in plants like mistletoe and crotalaria; the carples mature before the stamen (protogyny). In sunflower and cotton stamen mature before the carpel (protandy)  - Cross pollination occurs in plants with self compatibility or self sterility where certain chemicals on the surface of the stigma prevents growth in the pollen tubes of pollens grain from the same flower","marks":"7.5","difficulty":"1"},{"id":"theory>Biology>2004>3>c>i","subject":"Biology","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Name three agent of pollination.","images":[],"marking_scheme":"- Insect  - Bat  - Wind  - Water","marks":"2","difficulty":"2"},{"id":"theory>Biology>2004>3>c>ii","subject":"Biology","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"State three features of wind-dispersed fruits/seeds.","images":[],"marking_scheme":"- The fruits or seeds have parachute like hairs   - The seeds have floss  - The seeds or fruits are not heavy in weight  - The seeds or fruits have fluttering type of motion  - The seeds or fruits have winged seeds","marks":"2","difficulty":"2"},{"id":"theory>Biology>2004>4>a","subject":"Biology","year":"2004","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Describe an experiment to show that green plants require sunlight for photosynthesis (Details of test for starch not required)","images":[],"marking_scheme":"Experiment to show that green require sunlight for photosynthesis  METHOD: Firstly, de-starch two well watered potted plants by keeping them in dark cupboard for more than 24 hours. Test the leaves of both potted plant for starch by pouring drops of iodine at different places of the leaves. A negative result shows that there is no starch in the leaves. Then leave one of the potted plant in the dark cup-board to keep it in control. Put the other potted plant in sunlight for 4 - 6 hours. Pluck leaves from both potted plants in such a way that both the one in the dark cupboard and the one in the light are tested for starch in them.    OBSERVATION: Leaf from plant exposed to sunlight show presence of starch while that from the dark cup-board shows no starch.    CONCLUSION: This shows that light is necessary for photosynthesis.","marks":"8","difficulty":"3"},{"id":"theory>Biology>2004>4>b","subject":"Biology","year":"2004","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"What other conditions are necessary for photosynthesis?","images":[],"marking_scheme":"The other conditions that are necessary for photosynthesis are; water, chlorophyll, carbondioxide and suitable temperature.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2004>4>c","subject":"Biology","year":"2004","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Name the part of a dicotyledonous leaf where most food is manufactured, giving reasons.","images":[],"marking_scheme":"The site of dicotyledonous leaf where photosynthesis occurs is the palisade mesophyll layer. It occurs here because this layer contains more chlorophyll than the spongy layer or the other layers or part. The palisade layer is also located just below the upper epidermis where chlorophyll could absorb more sunlight.  OR  The part of a dicotyledonous leaf where most food is manufactured is the palisade mesophyll.    Reasons:  1. High Chloroplast Density: The palisade mesophyll cells contain a large number of chloroplasts, which are the organelles responsible for photosynthesis.  2. Optimal Position: These cells are located just below the upper epidermis, where they can receive the maximum amount of light.  3. Cell Arrangement: The elongated, closely packed arrangement of the palisade cells maximizes light absorption, enhancing the efficiency of photosynthesis.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2004>4>d","subject":"Biology","year":"2004","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"What happens to the manufactured food?","images":[],"marking_scheme":"The occurrences that happens to the manufactured food are;  - The manufactured food can be converted to cellulose to make cell wall or lipids.  - The manufactured food can be oxidised or broken down to produce energy.  - The manufactured food is translocated to various parts of the plant through the phloem.  - The manufactured food can combine with other elements such as nitrogen and sulphur to form proteins for growth.  - The manufactured food can be converted to starch and stored as starch.","marks":"7","difficulty":"2"},{"id":"theory>Biology>2004>5>a>i","subject":"Biology","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Explain briefly the term phenotype.","images":[],"marking_scheme":"Phenotype: This is the physical appearance or biochemical characteristic of an organism as a result of the interaction of its genotype and the environment.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2004>5>a>ii","subject":"Biology","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Explain briefly the term hybrid.","images":[],"marking_scheme":"Hybrid: This is the offspring of two parents that differ in one or more inheritable characteristics especially the offspring of two different varieties of the same species or two parents belonging to different species.","marks":"3","difficulty":"1"},{"id":"theory>Biology>2004>5>a>iii","subject":"Biology","year":"2004","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Explain briefly the term dominant character.","images":[],"marking_scheme":"Dominant character: This is an inherited characteristic that appears in an offspring if it is contributed from a parent through a dominant allele.","marks":"3","difficulty":"1"},{"id":"theory>Biology>2004>5>b>i","subject":"Biology","year":"2004","type":"Theory","sub_label":"i","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"Two varieties of maize, one with yellow (Y) grains and the other with purple (y) grains were crossed and all their offspring had yellow grains. When the offspring were crossed with the parent variety with purple grains, half of the resulting offspring had yellow grains, while the other half had purple grains.  Using labelled diagrams only;    deduce the genotype of the grains of the first filial generation.","images":["data:image/png;base64,"],"marking_scheme":"The genotype of the trait of the first filial generation.","marks":"5","difficulty":"3"},{"id":"theory>Biology>2004>5>b>ii","subject":"Biology","year":"2004","type":"Theory","sub_label":"ii","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"Two varieties of maize, one with yellow (Y) grains and the other with purple (y) grains were crossed and all their offspring had yellow grains. When the offspring were crossed with the parent variety with purple grains, half of the resulting offspring had yellow grains, while the other half had purple grains.  Using labelled diagrams only;  show the results of the cross between the first filial generation and the parent purple variety.","images":["data:image/png;base64,"],"marking_scheme":"The results of the cross between the first filial generation and the parent purple variety.","marks":"5","difficulty":"3"},{"id":"theory>Biology>2004>5>c","subject":"Biology","year":"2004","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE","question":"Mention two ways in which the applications of genetics is beneficial to agriculture.","images":[],"marking_scheme":"The applications of genetics is beneficial to agriculture in the following ways:  i. The process of genetic engineering introduce genes of desires traits into an organism.  ii. To produce hybrid vigour (i.e superior characters) when crossbreeding of plants or animals to produce offspring.  iii. In-breeding of desirables traits to obtain pure breed.  iv. It is applicable in the practise of crop selection to obtain varieties of animals or crops with qualities such as early maturity, higher yield, resistant to diseases.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2004>6>a","subject":"Biology","year":"2004","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Describe six protective adaptation used by animals against predation and give one example in each case.","images":[],"marking_scheme":"- Some mimic objects such as leaves or twigs e.g praying mantis, moths, stick insect.  - Some can inflate their body to frighten predator e.g octopus, cats, chameleon.  - Some can roll into a ball e.g pangolin, millipede, porcupine.  - Some have mechanical protection or shell e.g tortoise, barnacles, snail.  - Some can move very fast to escape from predators e.g antelopes.  - Some can produce ink or coloured substance to impair vision of predator or create a screen e.g squid.  - Some have chemical protection or poisonous secretions of skin glands e.g Toad.","marks":"10","difficulty":"2"},{"id":"theory>Biology>2004>6>b>i","subject":"Biology","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE","question":"What is pollution?","images":[],"marking_scheme":"This is the release of harmful waste products or materials into the environment by human activities which can be directly or indirectly to an extend whereby it affects living organism (plants and animals).","marks":"3","difficulty":"1"},{"id":"theory>Biology>2004>6>b>ii","subject":"Biology","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE","question":"State six human activities which cause pollution.","images":[],"marking_scheme":"- The release of harmful chemicals from mines  - Dumping of untreated sewage  - By drastic dumping of domestic and farm refuse  - By dumping plastics, broken bottles and glasses  - The release of heavy chemicals into the water bodies by factories, breweries or laboratories  - By not applying agro-chemicals rightly  - By spraying pesticides and herbicides","marks":"6","difficulty":"1"}];